('Crossbow, heavy', 'weapon', '', 18, 50, 'gp', '[{"index":"ammunition","name":"Ammunition","url":"/api/2014/weapon-properties/ammunition"},{"index":"heavy","name":"Heavy","url":"/api/2014/weapon-properties/heavy"},{"index":"loading","name":"Loading","url":"/api/2014/weapon-properties/loading"},{"index":"two-handed","name":"Two-Handed","url":"/api/2014/weapon-properties/two-handed"}]'::jsonb, '1d10', 'Piercing', NULL),
('Longbow', 'weapon', '', 2, 50, 'gp', '[{"index":"ammunition","name":"Ammunition","url":"/api/2014/weapon-properties/ammunition"},{"index":"heavy","name":"Heavy","url":"/api/2014/weapon-properties/heavy"},{"index":"two-handed","name":"Two-Handed","url":"/api/2014/weapon-properties/two-handed"}]'::jsonb, '1d8', 'Piercing', NULL),
('Net', 'weapon', '', 3, 1, 'gp', '[{"index":"thrown","name":"Thrown","url":"/api/2014/weapon-properties/thrown"},{"index":"special","name":"Special","url":"/api/2014/weapon-properties/special"}]'::jsonb, NULL, NULL, NULL),
('Berserker Axe', 'weapon', 'Weapon (any axe), rare (requires attunement)\nYou gain a +1 bonus to Attack and Damage Rolls made with this Magic Weapon. In addition, while you are attuned to this weapon, your Hit Points maximum increases by 1 for each level you have attained.\n***Curse.*** This axe is Cursed, and becoming attuned to it extends the curse to you. As long as you remain Cursed, you are unwilling to part with the axe, keeping it within reach at all times. You also have disadvantage on Attack rolls with Weapons other than this one, unless no foe is within 60 feet of you that you can see or hear.\nWhenever a Hostile creature damages you while the axe is in your possession, you must succeed on a DC 15 Wisdom saving throw or go berserk. While berserk, you must use your action each round to Attack the creature nearest to you with the axe. If you can make extra attacks as part of the Attack action, you use those extra attacks, moving to Attack the next nearest creature after you fell your current target. If you have multiple possible Targets, you Attack one at random. You are berserk until you start Your Turn with no creatures within 60 feet of you that you can see or hear.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Dagger of Venom', 'weapon', 'Weapon (dagger), rare\nYou gain a +1 bonus to attack and damage rolls made with this magic weapon.\nYou can use an action to cause thick, black poison to coat the blade. The poison remains for 1 minute or until an attack using this weapon hits a creature. That creature must succeed on a DC 15 Constitution saving throw or take 2d10 poison damage and become poisoned for 1 minute. The dagger can''t be used this way again until the next dawn.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Dancing Sword', 'weapon', 'Weapon (any sword), very rare (requires attunement)\nYou can use a bonus action to toss this magic sword into the air and speak the command word. When you do so, the sword begins to hover, flies up to 30 feet, and attacks one creature of your choice within 5 feet of it. The sword uses your attack roll and ability score modifier to damage rolls.\nWhile the sword hovers, you can use a bonus action to cause it to fly up to 30 feet to another spot within 30 feet of you. As part of the same bonus action, you can cause the sword to attack one creature within 5 feet of it.\nAfter the hovering sword attacks for the fourth time, it flies up to 30 feet and tries to return to your hand. If you have no hand free, it falls to the ground at your feet. If the sword has no unobstructed path to you, it moves as close to you as it can and then falls to the ground. It also ceases to hover if you grasp it or move more than 30 feet away from it.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Defender', 'weapon', 'Weapon (any sword), legendary (requires attunement)\nYou gain a +3 bonus to attack and damage rolls made with this magic weapon.\nThe first time you attack with the sword on each of your turns, you can transfer some or all of the sword''s bonus to your Armor Class, instead of using the bonus on any attacks that turn. For example, you could reduce the bonus to your attack and damage rolls to +1 and gain a +2 bonus to AC. The adjusted bonuses remain in effect until the start of your next turn, although you must hold the sword to gain a bonus to AC from it.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Dragon Slayer', 'weapon', 'Weapon (any sword), rare\nYou gain a +1 bonus to attack and damage rolls made with this magic weapon.\nWhen you hit a dragon with this weapon, the dragon takes an extra 3d6 damage of the weapon''s type. For the purpose of this weapon, "dragon" refers to any creature with the dragon type, including dragon turtles and wyverns.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Dwarven Thrower', 'weapon', 'Weapon (warhammer), very rare (requires attunement by a dwarf)\nYou gain a +3 bonus to attack and damage rolls made with this magic weapon. It has the thrown property with a normal range of 20 feet and a long range of 60 feet. When you hit with a ranged attack using this weapon, it deals an extra 1d8 damage or, if the target is a giant, 2d8 damage. Immediately after the attack, the weapon flies back to your hand.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Flame Tongue', 'weapon', 'Weapon (any sword), rare (requires attunement)\nYou can use a bonus action to speak this magic sword''s command word, causing flames to erupt from the blade. These flames shed bright light in a 40-foot radius and dim light for an additional 40 feet. While the sword is ablaze, it deals an extra 2d6 fire damage to any target it hits. The flames last until you use a bonus action to speak the command word again or until you drop or sheathe the sword.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Frost Brand', 'weapon', 'Weapon (any sword), very rare (requires attunement)\nWhen you hit with an attack using this magic sword, the target takes an extra 1d6 cold damage. In addition, while you hold the sword, you have resistance to fire damage.\nIn freezing temperatures, the blade sheds bright light in a 10-foot radius and dim light for an additional 10 feet.\nWhen you draw this weapon, you can extinguish all nonmagical flames within 30 feet of you. This property can be used no more than once per hour.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Giant Slayer', 'weapon', 'Weapon (any axe or sword), rare\nYou gain a +1 bonus to attack and damage rolls made with this magic weapon.\nWhen you hit a giant with it, the giant takes an extra 2d6 damage of the weapon''s type and must succeed on a DC 15 Strength saving throw or fall prone. For the purpose of this weapon, "giant" refers to any creature with the giant type, including ettins and trolls.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Hammer of Thunderbolts', 'weapon', 'Weapon (maul), legendary\nYou gain a +1 bonus to attack and damage rolls made with this magic weapon.\nGiant''s Bane (Requires Attunement). You must be wearing a belt of giant strength (any variety) and gauntlets of ogre power to attune to this weapon. The attunement ends if you take off either of those items. While you are attuned to this weapon and holding it, your Strength score increases by 4 and can exceed 20, but not 30. When you roll a 20 on an attack roll made with this weapon against a giant, the giant must succeed on a DC 17 Constitution saving throw or die.\nThe hammer also has 5 charges. While attuned to it, you can expend 1 charge and make a ranged weapon attack with the hammer, hurling it as if it had the thrown property with a normal range of 20 feet and a long range of 60 feet. If the attack hits, the hammer unleashes a thunderclap audible out to 300 feet. The target and every creature within 30 feet of it must succeed on a DC 17 Constitution saving throw or be stunned until the end of your next turn. The hammer regains 1d4 + 1 expended charges daily at dawn.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Holy Avenger', 'weapon', 'Weapon (any sword), legendary (requires attunement by a paladin)\nYou gain a +3 bonus to attack and damage rolls made with this magic weapon. When you hit a fiend or an undead with it, that creature takes an extra 2d10 radiant damage.\nWhile you hold the drawn sword, it creates an aura in a 10-foot radius around you. You and all creatures friendly to you in the aura have advantage on saving throws against spells and other magical effects. If you have 17 or more levels in the paladin class, the radius of the aura increases to 30 feet.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Javelin of Lightning', 'weapon', 'Weapon (javelin), uncommon\nThis javelin is a magic weapon. When you hurl it and speak its command word, it transforms into a bolt of lightning, forming a line 5 feet wide that extends out from you to a target within 120 feet. Each creature in the line excluding you and the target must make a DC 13 Dexterity saving throw, taking 4d6 lightning damage on a failed save, and half as much damage on a successful one. The lightning bolt turns back into a javelin when it reaches the target. Make a ranged weapon attack against the target. On a hit, the target takes damage from the javelin plus 4d6 lightning damage.\nThe javelin''s property can''t be used again until the next dawn. In the meantime, the javelin can still be used as a magic weapon.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Luck Blade', 'weapon', 'Weapon (any sword), legendary (requires attunement)\nYou gain a +1 bonus to attack and damage rolls made with this magic weapon. While the sword is on your person, you also gain a +1 bonus to saving throws.\n***Luck.*** If the sword is on your person, you can call on its luck (no action required) to reroll one attack roll, ability check, or saving throw you dislike. You must use the second roll. This property can''t be used again until the next dawn.\n***Wish.*** The sword has 1d4 - 1 charges. While holding it, you can use an action to expend 1 charge and cast the wish spell from it. This property can''t be used again until the next dawn. The sword loses this property if it has no charges.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Mace of Disruption', 'weapon', 'Weapon (mace), rare (requires attunement)\nWhen you hit a fiend or an undead with this magic weapon, that creature takes an extra 2d6 radiant damage. If the target has 25 hit points or fewer after taking this damage, it must succeed on a DC 15 Wisdom saving throw or be destroyed. On a successful save, the creature becomes frightened of you until the end of your next turn.\nWhile you hold this weapon, it sheds bright light in a 20-foot radius and dim light for an additional 20 feet.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Mace of Smiting', 'weapon', 'Weapon (mace), rare\nYou gain a +1 bonus to attack and damage rolls made with this magic weapon. The bonus increases to +3 when you use the mace to attack a construct.\nWhen you roll a 20 on an attack roll made with this weapon, the target takes an extra 2d6 bludgeoning damage, or 4d6 bludgeoning damage if it''s a construct. If a construct has 25 hit points or fewer after taking this damage, it is destroyed.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Mace of Terror', 'weapon', 'Weapon (mace), rare (requires attunement)\nThis magic weapon has 3 charges. While holding it, you can use an action and expend 1 charge to release a wave of terror. Each creature of your choice in a 30-foot radius extending from you must succeed on a DC 15 Wisdom saving throw or become frightened of you for 1 minute. While it is frightened in this way, a creature must spend its turns trying to move as far away from you as it can, and it can''t willingly move to a space within 30 feet of you. It also can''t take reactions. For its action, it can use only the Dash action or try to escape from an effect that prevents it from moving. If it has nowhere it can move, the creature can use the Dodge action. At the end of each of its turns, a creature can repeat the saving throw, ending the effect on itself on a success.\nThe mace regains 1d3 expended charges daily at dawn.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Nine Lives Stealer', 'weapon', 'Weapon (any sword), very rare (requires attunement)\nYou gain a +2 bonus to attack and damage rolls made with this magic weapon.\nThe sword has 1d8 + 1 charges. If you score a critical hit against a creature that has fewer than 100 hit points, it must succeed on a DC 15 Constitution saving throw or be slain instantly as the sword tears its life force from its body (a construct or an undead is immune). The sword loses 1 charge if the creature is slain. When the sword has no charges remaining, it loses this property.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Oathbow', 'weapon', 'Weapon (longbow), very rare (requires attunement)\nWhen you nock an arrow on this bow, it whispers in Elvish, "Swift defeat to my enemies." When you use this weapon to make a ranged attack, you can, as a command phrase, say, "Swift death to you who have wronged me." The target of your attack becomes your sworn enemy until it dies or until dawn seven days later. You can have only one such sworn enemy at a time. When your sworn enemy dies, you can choose a new one after the next dawn.\nWhen you make a ranged attack roll with this weapon against your sworn enemy, you have advantage on the roll. In addition, your target gains no benefit from cover, other than total cover, and you suffer no disadvantage due to long range. If the attack hits, your sworn enemy takes an extra 3d6 piercing damage.\nWhile your sworn enemy lives, you have disadvantage on attack rolls with all other weapons.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Scimitar of Speed', 'weapon', 'Weapon (scimitar), very rare (requires attunement)\nYou gain a +2 bonus to attack and damage rolls made with this magic weapon. In addition, you can make one attack with it as a bonus action on each of your turns.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Sun Blade', 'weapon', 'Weapon (longsword), rare (requires attunement)\nThis item appears to be a longsword hilt. While grasping the hilt, you can use a bonus action to cause a blade of pure radiance to spring into existence, or make the blade disappear. While the blade exists, this magic longsword has the finesse property. If you are proficient with shortswords or longswords, you are proficient with the sun blade.\nYou gain a +2 bonus to attack and damage rolls made with this weapon, which deals radiant damage instead of slashing damage. When you hit an undead with it, that target takes an extra 1d8 radiant damage.\nThe sword''s luminous blade emits bright light in a 15-foot radius and dim light for an additional 15 feet. The light is sunlight. While the blade persists, you can use an action to expand or reduce its radius of bright and dim light by 5 feet each, to a maximum of 30 feet each or a minimum of 10 feet each.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Sword of Life Stealing', 'weapon', 'Weapon (any sword), rare (requires attunement)\nWhen you attack a creature with this magic weapon and roll a 20 on the attack roll, that target takes an extra 3d6 necrotic damage, provided that the target isn''t a construct or an undead. You gain temporary hit points equal to the extra damage dealt.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Sword of Sharpness', 'weapon', 'Weapon (any sword that deals slashing damage), very rare (requires attunement)\nWhen you attack an object with this magic sword and hit, maximize your weapon damage dice against the target.\nWhen you attack a creature with this weapon and roll a 20 on the attack roll, that target takes an extra 4d6 slashing damage. Then roll another d20. If you roll a 20, you lop off one of the target''s limbs, with the effect of such loss determined by the GM. If the creature has no limb to sever, you lop off a portion of its body instead.\nIn addition, you can speak the sword''s command word to cause the blade to shed bright light in a 10 foot radius and dim light for an additional 10 feet. Speaking the command word again or sheathing the sword puts out the light.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Sword of Wounding', 'weapon', 'Weapon (any sword), rare (requires attunement)\nHit points lost to this weapon''s damage can be regained only through a short or long rest, rather than by regeneration, magic, or any other means.\nOnce per turn, when you hit a creature with an attack using this magic weapon, you can wound the target. At the start of each of the wounded creature''s turns, it takes 1d4 necrotic damage for each time you''ve wounded it, and it can then make a DC 15 Constitution saving throw, ending the effect of all such wounds on itself on a success. Alternatively, the wounded creature, or a creature within 5 feet of it, can use an action to make a DC 15 Wisdom (Medicine) check, ending the effect of such wounds on it on a success.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Trident of Fish Command', 'weapon', 'Weapon (trident), uncommon (requires attunement)\nThis trident is a magic weapon. It has 3 charges. While you carry it, you can use an action and expend 1 charge to cast dominate beast (save DC 15) from it on a beast that has an innate swimming speed. The trident regains 1d3 expended charges daily at dawn.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Vicious Weapon', 'weapon', 'Weapon (any), rare\nWhen you roll a 20 on your attack roll with this magic weapon, your critical hit deals an extra 2d6 damage of the weapon''s type.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Vorpal Sword', 'weapon', 'Weapon (any sword that deals slashing damage), legendary (requires attunement)\nYou gain a +3 bonus to attack and damage rolls made with this magic weapon. In addition, the weapon ignores resistance to slashing damage.\nWhen you attack a creature that has at least one head with this weapon and roll a 20 on the attack roll, you cut off one of the creature''s heads. The creature dies if it can''t survive without the lost head. A creature is immune to this effect if it is immune to slashing damage, doesn''t have or need a head, has legendary actions, or the GM decides that the creature is too big for its head to be cut off with this weapon. Such a creature instead takes an extra 6d8 slashing damage from the hit.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Weapon, +1, +2, or +3', 'weapon', 'Weapon (any), uncommon (+1), rare (+2), or very rare (+3)\nYou have a bonus to attack and damage rolls made with this magic weapon. The bonus is determined by the weapon''s rarity.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Weapon, +1', 'weapon', 'Weapon (any), uncommon\nYou have a +1 bonus to attack and damage rolls made with this magic weapon.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Weapon, +2', 'weapon', 'Weapon (any), rare\nYou have a +2 bonus to attack and damage rolls made with this magic weapon.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL),
('Weapon, +3', 'weapon', 'Weapon (any), very rare\nYou have a +3 bonus to attack and damage rolls made with this magic weapon.', 0, 0, 'gp', '[]'::jsonb, NULL, NULL, NULL)
INSERT INTO public.game_items (name, item_type, description, weight, cost_quantity, cost_unit, properties, damage_dice, damage_type, armor_class) VALUES
('Padded Armor', 'armor', '', 8, 5, 'gp', '{"stealth_disadvantage":true,"str_minimum":0}'::jsonb, NULL, NULL, 11),
('Leather Armor', 'armor', '', 10, 10, 'gp', '{"stealth_disadvantage":false,"str_minimum":0}'::jsonb, NULL, NULL, 11),
('Studded Leather Armor', 'armor', '', 13, 45, 'gp', '{"stealth_disadvantage":false,"str_minimum":0}'::jsonb, NULL, NULL, 12),
('Hide Armor', 'armor', '', 12, 10, 'gp', '{"stealth_disadvantage":false,"str_minimum":0}'::jsonb, NULL, NULL, 12),
('Chain Shirt', 'armor', '', 20, 50, 'gp', '{"stealth_disadvantage":false,"str_minimum":0}'::jsonb, NULL, NULL, 13),
('Scale Mail', 'armor', '', 45, 50, 'gp', '{"stealth_disadvantage":true,"str_minimum":0}'::jsonb, NULL, NULL, 14),
('Breastplate', 'armor', '', 20, 400, 'gp', '{"stealth_disadvantage":false,"str_minimum":0}'::jsonb, NULL, NULL, 14),
('Half Plate Armor', 'armor', '', 40, 750, 'gp', '{"stealth_disadvantage":true,"str_minimum":0}'::jsonb, NULL, NULL, 15),
('Ring Mail', 'armor', '', 40, 30, 'gp', '{"stealth_disadvantage":true,"str_minimum":0}'::jsonb, NULL, NULL, 14),
('Chain Mail', 'armor', '', 55, 75, 'gp', '{"stealth_disadvantage":true,"str_minimum":13}'::jsonb, NULL, NULL, 16),
('Splint Armor', 'armor', '', 60, 200, 'gp', '{"stealth_disadvantage":true,"str_minimum":15}'::jsonb, NULL, NULL, 17),
('Plate Armor', 'armor', '', 65, 1500, 'gp', '{"stealth_disadvantage":true,"str_minimum":15}'::jsonb, NULL, NULL, 18),
('Shield', 'armor', '', 6, 10, 'gp', '{"stealth_disadvantage":false,"str_minimum":0}'::jsonb, NULL, NULL, 2),
('Adamantine Armor', 'armor', 'Armor (medium or heavy, but not hide), uncommon\nThis suit of armor is reinforced with adamantine, one of the hardest substances in existence. While you''re wearing it, any critical hit against you becomes a normal hit.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Animated Shield', 'armor', 'Armor (shield), very rare (requires attunement)\nWhile holding this shield, you can speak its command word as a bonus action to cause it to animate. The shield leaps into the air and hovers in your space to protect you as if you were wielding it, leaving your hands free. The shield remains animated for 1 minute, until you use a bonus action to end this effect, or until you are incapacitated or die, at which point the shield falls to the ground or into your hand if you have one free.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Armor, +1, +2, or +3', 'armor', 'Armor (light, medium, or heavy), rare (+1), very rare (+2), or legendary (+3)\nYou have a bonus to AC while wearing this armor. The bonus is determined by its rarity.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Armor of Invulnerability', 'armor', 'Armor (plate), legendary (requires attunement)\nYou have resistance to nonmagical damage while you wear this armor. Additionally, you can use an action to make yourself immune to nonmagical damage for 10 minutes or until you are no longer wearing the armor. Once this special action is used, it can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Armor of Resistance', 'armor', 'Armor (light, medium, or heavy), rare (requires attunement)\nYou have resistance to one type of damage while you wear this armor. The GM chooses the type or determines it randomly from the options below.\n| d10 | Damage Type |\n|---|---|\n| 1 | Acid |\n| 2 | Cold |\n| 3 | Fire |\n| 4 | Force |\n| 5 | Lightning |\n| 6 | Necrotic |\n| 7 | Poison |\n| 8 | Psychic |\n| 9 | Radiant |\n| 10 | Thunder |', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Armor of Vulnerability', 'armor', 'Armor (plate), rare (requires attunement)\nWhile wearing this armor, you have resistance to  one of the following damage types: bludgeoning, piercing, or slashing. The GM chooses the type or determines it randomly.\n***Curse.*** This armor is cursed, a fact that is revealed only when an identify spell is cast on the armor or you attune to it. Attuning to the armor curses you until you are targeted by the remove curse spell or similar magic; removing the armor fails to end the curse. While cursed, you have vulnerability to two of the three damage types associated with the armor (not the one to which it grants resistance).', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Arrow-Catching Shield', 'armor', 'Armor (shield), rare (requires attunement)\nYou gain a +2 bonus to AC against ranged attacks while you wield this shield. This bonus is in addition to the shield''s normal bonus to AC. In addition, whenever an attacker makes a ranged attack against a target within 5 feet of you, you can use your reaction to become the target of the attack instead.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Demon Armor', 'armor', 'Armor (plate), very rare (requires attunement)\nWhile wearing this armor, you gain a +1 bonus to AC, and you can understand and speak Abyssal. In addition, the armor''s clawed gauntlets turn unarmed strikes with your hands into magic weapons that deal slashing damage, with a +1 bonus to attack rolls and damage rolls and a damage die of 1d8.\n***Curse.*** Once you don this cursed armor, you can''t doff it unless you are targeted by the remove curse spell or similar magic. While wearing the armor, you have disadvantage on attack rolls against demons and on saving throws against their spells and special abilities.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Dragon Scale Mail', 'armor', 'Armor (scale mail), very rare (requires attunement)\nDragon scale mail is made of the scales of one kind of dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.\nWhile wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to one damage type that is determined by the kind of dragon that provided the scales (see the table).\nAdditionally, you can focus your senses as an action to magically discern the distance and direction to the closest dragon within 30 miles of you that is of the same type as the armor. This special action can''t be used again until the next dawn.\n| Dragon | Resistance |\n|---|---|\n| Black | Acid |\n| Blue | Lightning |\n| Brass | Fire |\n| Bronze | Lightning |\n| Copper | Acid |\n| Gold | Fire |\n| Green | Poison |\n| Red | Fire |\n| Silver | Cold |\n| White | Cold |', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Dwarven Plate', 'armor', 'Armor (plate), very rare\nWhile wearing this armor, you gain a +2 bonus to AC. In addition, if an effect moves you against your will along the ground, you can use your reaction to reduce the distance you are moved by up to 10 feet.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Elven Chain', 'armor', 'Armor (chain shirt), rare\nYou gain a +1 bonus to AC while you wear this armor. You are considered proficient with this armor even if you lack proficiency with medium armor.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Glamoured Studded Leather Armor', 'armor', 'Armor (studded leather), rare\nWhile wearing this armor, you gain a +1 bonus to AC. You can also use a bonus action to speak the armor''s command word and cause the armor to assume the appearance of a normal set of clothing or some other kind of armor. You decide what it looks like, including color, style, and accessories, but the armor retains its normal bulk and weight. The illusory appearance lasts until you use this property again or remove the armor.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Mithral Armor', 'armor', 'Armor (medium or heavy), uncommon\nMithral is a light, flexible metal. A mithral chain shirt or breastplate can be worn under normal clothes. If the armor normally imposes disadvantage on Dexterity (Stealth) checks or has a Strength requirement, the mithral version of the armor doesn''t.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Plate Armor of Etherealness', 'armor', 'Armor (plate), legendary (requires attunement)\nWhile you''re wearing this armor, you can speak its command word as an action to gain the effect of the etherealness spell, which last for 10 minutes or until you remove the armor or use an action to speak the command word again. This property of the armor can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Shield of Missile Attraction', 'armor', 'Armor (shield), rare (requires attunement)\nWhile holding this shield, you have resistance to damage from ranged weapon attacks.\n***Curse.*** This shield is cursed. Attuning to it curses you until you are targeted by the remove curse spell or similar magic. Removing the shield fails to end the curse on you. Whenever a ranged weapon attack is made against a target within 10 feet of you, the curse causes you to become the target instead.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Spellguard Shield', 'armor', 'Armor (shield), very rare (requires attunement)\nWhile holding this shield, you have advantage on saving throws against spells and other magical effects, and spell attacks have disadvantage against you.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Armor, +1', 'armor', 'Armor (light, medium, or heavy), rare\nYou have a +1 bonus to AC while wearing this armor.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Armor, +2', 'armor', 'Armor (light, medium, or heavy), very rare\nYou have a +2 bonus to AC while wearing this armor.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Armor, +3', 'armor', 'Armor (light, medium, or heavy), legendary\nYou have a +3 bonus to AC while wearing this armor.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Black Dragon Scale Mail', 'armor', 'Armor (scale mail), very rare (requires attunement)\nDragon scale mail is made of the scales of a black dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.\nWhile wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to acid damage.\nAdditionally, you can focus your senses as an action to magically discern the distance and direction to the closest black dragon within 30 miles of you. This special action can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Blue Dragon Scale Mail', 'armor', 'Armor (scale mail), very rare (requires attunement)\nDragon scale mail is made of the scales of a blue dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.\nWhile wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to lightning damage.\nAdditionally, you can focus your senses as an action to magically discern the distance and direction to the closest blue dragon within 30 miles of you. This special action can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Brass Dragon Scale Mail', 'armor', 'Armor (scale mail), very rare (requires attunement)\nDragon scale mail is made of the scales of a brass dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.\nWhile wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to fire damage.\nAdditionally, you can focus your senses as an action to magically discern the distance and direction to the closest brass dragon within 30 miles of you. This special action can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Bronze Dragon Scale Mail', 'armor', 'Armor (scale mail), very rare (requires attunement)\nDragon scale mail is made of the scales of a bronze dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.\nWhile wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to lightning damage.\nAdditionally, you can focus your senses as an action to magically discern the distance and direction to the closest bronze dragon within 30 miles of you. This special action can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Copper Dragon Scale Mail', 'armor', 'Armor (scale mail), very rare (requires attunement)\nDragon scale mail is made of the scales of a copper dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.\nWhile wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to acid damage.\nAdditionally, you can focus your senses as an action to magically discern the distance and direction to the closest copper dragon within 30 miles of you. This special action can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Gold Dragon Scale Mail', 'armor', 'Armor (scale mail), very rare (requires attunement)\nDragon scale mail is made of the scales of a gold dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.\nWhile wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to fire damage.\nAdditionally, you can focus your senses as an action to magically discern the distance and direction to the closest gold dragon within 30 miles of you. This special action can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Green Dragon Scale Mail', 'armor', 'Armor (scale mail), very rare (requires attunement)\nDragon scale mail is made of the scales of a green dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.\nWhile wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to poison damage.\nAdditionally, you can focus your senses as an action to magically discern the distance and direction to the closest green dragon within 30 miles of you. This special action can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Red Dragon Scale Mail', 'armor', 'Armor (scale mail), very rare (requires attunement)\nDragon scale mail is made of the scales of a red dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.\nWhile wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to fire damage.\nAdditionally, you can focus your senses as an action to magically discern the distance and direction to the closest red dragon within 30 miles of you. This special action can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('Silver Dragon Scale Mail', 'armor', 'Armor (scale mail), very rare (requires attunement)\nDragon scale mail is made of the scales of a silver dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.\nWhile wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to cold damage.\nAdditionally, you can focus your senses as an action to magically discern the distance and direction to the closest silver dragon within 30 miles of you. This special action can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0),
('White Dragon Scale Mail', 'armor', 'Armor (scale mail), very rare (requires attunement)\nDragon scale mail is made of the scales of a white dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.\nWhile wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to cold damage.\nAdditionally, you can focus your senses as an action to magically discern the distance and direction to the closest white dragon within 30 miles of you. This special action can''t be used again until the next dawn.', 0, 0, 'gp', '{}'::jsonb, NULL, NULL, 0)
INSERT INTO public.backgrounds (name, description, skill_proficiencies, tool_proficiencies, languages, starting_equipment, feature_name, feature_description) VALUES
('Acolyte', '', '[{"index":"skill-insight","name":"Skill: Insight","url":"/api/2014/proficiencies/skill-insight"},{"index":"skill-religion","name":"Skill: Religion","url":"/api/2014/proficiencies/skill-religion"}]'::jsonb, '[]'::jsonb, '{"choose":2,"type":"languages","from":{"option_set_type":"resource_list","resource_list_url":"/api/2014/languages"}}'::jsonb, '[{"equipment":{"index":"clothes-common","name":"Clothes, common","url":"/api/2014/equipment/clothes-common"},"quantity":1},{"equipment":{"index":"pouch","name":"Pouch","url":"/api/2014/equipment/pouch"},"quantity":1}]'::jsonb, 'Shelter of the Faithful', 'As an acolyte, you command the respect of those who share your faith, and you can perform the religious ceremonies of your deity. You and your adventuring companions can expect to receive free healing and care at a temple, shrine, or other established presence of your faith, though you must provide any material components needed for spells. Those who share your religion will support you (but only you) at a modest lifestyle.\nYou might also have ties to a specific temple dedicated to your chosen deity or pantheon, and you have a residence there. This could be the temple where you used to serve, if you remain on good terms with it, or a temple where you have found a new home. While near your temple, you can call upon the priests for assistance, provided the assistance you ask for is not hazardous and you remain in good standing with your temple.')
